const input = $input.first().json;
if (!input || !input.userId) {
  throw new Error('RAG Indexer requiere userId');
}

const { userId, query } = input;
let eventType, eventData;

// Strategy 1: Try to parse query as JSON (the expected format from AI agent)
if (query) {
  try {
    const parsed = JSON.parse(query);
    if (parsed.eventType) {
      eventType = parsed.eventType;
      const { eventType: _, ...rest } = parsed;
      eventData = rest;
    }
  } catch(e) {
    // Not valid JSON — fall back to pattern matching
  }
}

// Strategy 2: Pattern matching for common Spanish weight/meal phrases
if (!eventType && query) {
  const q = query.toLowerCase();
  // Weight patterns: "peso 77 kg", "78 kilos", "weight_log: 77"
  const weightMatch = q.match(/(?:peso|weight)[:\s]+(\d+(?:[.,]\d+)?)\s*(?:kg|kilos?)?/i) ||
                      q.match(/(\d+(?:[.,]\d+)?)\s*(?:kg|kilos?)/i);
  // Meal patterns
  const mealMatch = q.match(/(?:comi|desayun|almorz|cen|eat|ate|meal)[:\s]+(.+)/i);
  // Goal patterns
  const goalMatch = q.match(/(?:meta|objetivo|goal)[:\s]+(.+)/i);

  if (weightMatch) {
    eventType = 'weight_log';
    const kg = parseFloat(weightMatch[1].replace(',', '.'));
    eventData = { weight_kg: kg };
  } else if (mealMatch) {
    eventType = 'meal_reported';
    eventData = { meal_description: mealMatch[1].trim() };
  } else if (goalMatch) {
    eventType = 'goal_set';
    eventData = { description: goalMatch[1].trim() };
  } else {
    eventType = 'general';
    eventData = { description: query };
  }
}

if (!eventType) {
  throw new Error('No se pudo determinar eventType del query: ' + query);
}

const now = (eventData && eventData.date) ? eventData.date : new Date().toLocaleDateString('en-CA', { timeZone: 'America/Bogota' });
let text = '';

switch (eventType) {
  case 'weight_log':
    text = `On ${now}, user logged weight: ${eventData.weight_kg}kg`;
    if (eventData.notes) text += `. Notes: ${eventData.notes}`;
    break;
  case 'meal_reported':
    text = `On ${now}, user ate: ${eventData.meal_description}`;
    if (eventData.calories) text += `. Estimated calories: ${eventData.calories} kcal`;
    if (eventData.meal_type) text += `. Meal type: ${eventData.meal_type}`;
    break;
  case 'profile_update':
    const changes = Object.entries(eventData)
      .filter(([k]) => k !== 'date')
      .map(([k, v]) => `${k}: ${v}`)
      .join(', ');
    text = `On ${now}, user updated profile: ${changes}`;
    break;
  case 'goal_set':
    text = `On ${now}, user set goal: ${eventData.goal_type || eventData.description || 'general'}`;
    if (eventData.target_weight_kg) text += `. Target weight: ${eventData.target_weight_kg}kg`;
    if (eventData.target_date) text += `. Target date: ${eventData.target_date}`;
    break;
  default:
    text = `On ${now}, user event: ${eventType}. Data: ${JSON.stringify(eventData)}`;
}

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Bogota' });
const idBase = `${userId}-${eventType}-${today}`;
const pointId = idBase.replace(/[^a-zA-Z0-9]/g, '').substring(0, 32).padEnd(32, '0');
const formattedId = [
  pointId.substring(0, 8),
  pointId.substring(8, 12),
  pointId.substring(12, 16),
  pointId.substring(16, 20),
  pointId.substring(20, 32)
].join('-');

return [{ json: { userId, eventType, eventData, text, pointId: formattedId, date: now } }];

